import tiktoken
enc = tiktoken.get_encoding('cl100k_base')

def monitor_context_window(agent):
    memory = agent.get_memory()
    tokens = len(enc.encode(memory.get_conversation_history()))
    if tokens > 120000:
        print(f'⚠️  CONTEXT OVERFLOW: {tokens} tokens')
        return {'alert': 'context_window_exceeded', 'tokens': tokens}
    return None

class MemoryGrowthDetector:
    def __init__(self):
        self.last_tokens = 0

    def check_growth(self, agent):
        current_tokens = len(enc.encode(agent.get_memory().conversation))
        growth_rate = current_tokens - self.last_tokens
        self.last_tokens = current_tokens

        if growth_rate > 5000:  # >5k tokens per turn
            return {'alert': 'unbounded_growth', 'rate': growth_rate}
        return None

from beeai.events import EventListener

class SerializationMonitor(EventListener):
    async def on_persistence_error(self, event):
        if 'SerializationError' in str(event.error):
            memory_size = len(str(event.agent_state))
            if memory_size > 10**6:  # >1MB
                print(f'🚨 SERIALIZATION FAILURE: {memory_size} bytes')
                return {'alert': 'context_serialization_failed'}
            return None

