def limit_tool_output(tool_output, max_tokens=2000):
    enc = tiktoken.get_encoding('cl100k_base')
    if len(enc.encode(tool_output)) <= max_tokens:
        return tool_output

    truncated = enc.decode(enc.encode(tool_output)[:max_tokens])
    return f'{truncated}... [truncated for context window]'

from beeai.memory import ConversationMemory

class CompressedMemory(ConversationMemory):
    def add_exchange(self, user_msg, agent_msg):
        if len(self.conversation) > 50:
            # Summarize oldest 50% of conversation
            old_history = self.conversation[:25]
            summary_prompt = f'Summarize: {"".join(old_history)}'
            summary = self.agent.model.generate(summary_prompt)  # Use Granite
            self.conversation = [summary] + self.conversation[25:]
        super().add_exchange(user_msg, agent_msg)

