from vex_sdk import Vex
vex = Vex(api_key='your-vex-key')

from beeai.events import EventBus

@vex.register_detector('beeai-context-window')
def detect_context_issues(event):
    if event.type == 'agent_turn_complete':
        agent = event.agent
        tokens = len(enc.encode(agent.get_memory().conversation))

        if tokens > 110000:
            vex.trigger_remediation(
                agent_id=agent.id,
                issue='context_overflow',
                fix='truncate_context',
                params={'max_tokens': 90000}
            )
            return {'severity': 'critical', 'tokens': tokens}

EventBus.register_listener(vex_listener=vex.process_event)
